Evaluate each order's best insertion across existing and empty assign slots via incremental cost comparison, rolling back failed trials, committing minimal positive delta inserts, and ensuring every order is placed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		feasible  bool
	}
	for shipIdx := range oris {
		best := candidate{-1, 1e30, false}
		orderID := total_ship + shipIdx
		ori := oris[shipIdx]
		des := dess[shipIdx]

		slotLimit := dispatch.AssignsLen
		if slotLimit == 0 {
			slotLimit = 1
		}

		for assignIdx := 0; assignIdx < MAXASSIGNS; assignIdx++ {
			isNewSlot := assignIdx >= dispatch.AssignsLen && assignIdx < MAXASSIGNS
			if isNewSlot {
				if slotLimit >= MAXASSIGNS || assignIdx != slotLimit {
					continue
				}
				if dispatch.Assigns[assignIdx].StationsLen > 0 {
					continue
				}
			}
			prevCost := dispatch.Assigns[assignIdx].Cost
			saved := prevCost
			inserted := dispatch.Assigns[assignIdx].AddShip(orderID, ori, des)
			if inserted {
				dispatch.Assigns[assignIdx].GenRoute()
				newCost := dispatch.Assigns[assignIdx].Cost
				delta := newCost - saved
				ok := newCost >= 0 && delta >= 0
				if ok {
					if delta < best.costDelta {
						best.assignIdx = assignIdx
						best.costDelta = delta
						best.feasible = true
					}
				}
				dispatch.Assigns[assignIdx].RemoveShip(orderID)
				dispatch.Assigns[assignIdx].GenRoute()
				if dispatch.Assigns[assignIdx].Cost < 0 {
					dispatch.Assigns[assignIdx].Cost = saved
				}
			}
		}

		targetIdx := -1
		if best.feasible {
			targetIdx = best.assignIdx
		} else {
			for i := 0; i < MAXASSIGNS; i++ {
				if i >= dispatch.AssignsLen && dispatch.Assigns[i].StationsLen == 0 {
					targetIdx = i
					break
				}
			}
			if targetIdx == -1 && dispatch.AssignsLen < MAXASSIGNS {
				targetIdx = dispatch.AssignsLen
			}
		}

		if targetIdx >= 0 {
