func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := 0; jj < len(oris); jj++ {
		bestDelta := 1e308
		bestIdx := -1
		bestForward := true
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			savedState := dispatch.Assigns[ii].CloneState()
			costBefore := dispatch.Assigns[ii].Cost
			if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[ii].GenRoute()
				delta := dispatch.Assigns[ii].Cost - costBefore
				if delta >= 0 && delta < bestDelta {
					bestDelta = delta
					bestIdx = ii
					bestForward = true
				}
				dispatch.Assigns[ii].RestoreState(savedState)
				dispatch.Assigns[ii].GenRoute()
			}
		}
		fallbackNew := false
		if bestIdx == -1 || (dispatch.AssignsLen < MAXASSIGNS && bestDelta > 0) {
			newIdx := dispatch.AssignsLen
			if newIdx < MAXASSIGNS {
				savedZero := dispatch.Assigns[newIdx].CloneState()
				if dispatch.Assigns[newIdx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
					dispatch.Assigns[newIdx].GenRoute()
					newDelta := dispatch.Assigns[newIdx].Cost
					if bestIdx == -1 || newDelta < bestDelta*1.5 {
						bestIdx = newIdx
						bestDelta = newDelta
						fallbackNew = true
					}
				}
				if !fallbackNew {
					dispatch.Assigns[newIdx].RestoreState(savedZero)
				}
			}
		}
		if bestIdx == -1 {
			for kk := 0; kk <= dispatch.AssignsLen; kk++ {
				idx := kk % (dispatch.AssignsLen + 1)
				if idx == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
