					if dispatch.Assigns[idx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
						dispatch.Assigns[idx].GenRoute()
						if dispatch.Assigns[idx].Cost >= 0 {
							break
						}
					}
					dispatch.Assigns[idx].RestoreState(savedSeed)
				}
			}
			continue
		}
		if !fallbackNew {
			savedCommit := dispatch.Assigns[bestIdx].CloneState()
			dispatch.Assigns[bestIdx].RestoreState(savedCommit)
			ok := dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
